  wide: ["Milattan Ă–nce", "Milattan Sonra"],
};

const quarterValues = {
  narrow: ["1", "2", "3", "4"],
  abbreviated: ["1Ă‡", "2Ă‡", "3Ă‡", "4Ă‡"],
  wide: ["Ä°lk Ă§eyrek", "Ä°kinci Ă‡eyrek", "ĂśĂ§ĂĽncĂĽ Ă§eyrek", "Son Ă§eyrek"],
};

const monthValues = {
  narrow: ["O", "Ĺž", "M", "N", "M", "H", "T", "A", "E", "E", "K", "A"],
  abbreviated: [
    "Oca",
    "Ĺžub",
    "Mar",
    "Nis",
    "May",
    "Haz",
    "Tem",
    "AÄźu",
