    "Kas",
    "Ara",
  ],

  wide: [
    "Ocak",
    "Ĺžubat",
    "Mart",
    "Nisan",
    "MayÄ±s",
    "Haziran",
    "Temmuz",
    "AÄźustos",
    "EylĂĽl",
    "Ekim",
    "KasÄ±m",
    "AralÄ±k",
  ],
};

const dayValues = {
  narrow: ["P", "P", "S", "Ă‡", "P", "C", "C"],
  short: ["Pz", "Pt", "Sa", "Ă‡a", "Pe", "Cu", "Ct"],
  abbreviated: ["Paz", "Pzt", "Sal", "Ă‡ar", "Per", "Cum", "Cts"],
  wide: [
    "Pazar",
    "Pazartesi",
    "SalÄ±",
    "Ă‡arĹźamba",
    "PerĹźembe",
    "Cuma",
    "Cumartesi",
  ],
};

const dayPeriodValues = {
  narrow: {
    am: "Ă¶Ă¶",
    pm: "Ă¶s",
    midnight: "gy",
    noon: "Ă¶",
    morning: "sa",
    afternoon: "Ă¶s",
    evening: "ak",
    night: "ge",
  },
  abbreviated: {
    am: "Ă–Ă–",
    pm: "Ă–S",
    midnight: "gece yarÄ±sÄ±",
    noon: "Ă¶Äźle",
    morning: "sabah",
    afternoon: "Ă¶Äźleden sonra",
    evening: "akĹźam",
    night: "gece",
  },
  wide: {
    am: "Ă–.Ă–.",
    pm: "Ă–.S.",
    midnight: "gece yarÄ±sÄ±",
    noon: "Ă¶Äźle",
    morning: "sabah",
    afternoon: "Ă¶Äźleden sonra",
    evening: "akĹźam",
    night: "gece",
  },
};

const formattingDayPeriodValues = {
  narrow: {
    am: "Ă¶Ă¶",
    pm: "Ă¶s",
    midnight: "gy",
    noon: "Ă¶",
    morning: "sa",
    afternoon: "Ă¶s",
    evening: "ak",
    night: "ge",
  },
  abbreviated: {
    am: "Ă–Ă–",
    pm: "Ă–S",
    midnight: "gece yarÄ±sÄ±",
    noon: "Ă¶Äźlen",
    morning: "sabahleyin",
    afternoon: "Ă¶Äźleden sonra",
    evening: "akĹźamleyin",
    night: "geceleyin",
  },
  wide: {
    am: "Ă¶.Ă¶.",
    pm: "Ă¶.s.",
    midnight: "gece yarÄ±sÄ±",
    noon: "Ă¶Äźlen",
    morning: "sabahleyin",
    afternoon: "Ă¶Äźleden sonra",
    evening: "akĹźamleyin",
    night: "geceleyin",
  },
};

const ordinalNumber = (dirtyNumber, _options) => {
  const number = Number(dirtyNumber);
  return number + ".";
};

export const localize = {
  ordinalNumber,

  era: buildLocalizeFn({
    values: eraValues,
    defaultWidth: "wide",
  }),

  quarter: buildLocalizeFn({
    values: quarterValues,
    defaultWidth: "wide",
    argumentCallback: (quarter) => Number(quarter) - 1,
  }),

  month: buildLocalizeFn({
    values: monthValues,
    defaultWidth: "wide",
  }),

  day: buildLocalizeFn({
    values: dayValues,
    defaultWidth: "wide",
  }),

  dayPeriod: buildLocalizeFn({
    values: dayPeriodValues,
    defaultWidth: "wide",
    formattingValues: formattingDayPeriodValues,
    defaultFormattingWidth: "wide",
